def merge_breaks(blocks):
    for li,rs in [(51,'Watch will'),(39,'Robert would')]:
        left,right=blocks[li],blocks[li+1]
        assert right['text'].startswith(rs)
        left['text']+=' '+right['text']; left['end_page']=right['end_page']; del blocks[li+1]
    for i,b in enumerate(blocks,1): b['order']=i; b['id']=f"CH21-P{int(b['page']):03d}-{i:03d}"
    return blocks

